-- Corrected India-focused seed data: 50 popular cars
-- Prices are approximate ex-showroom values in INR lakhs.
-- Mileage is km/l for ICE vehicles; EV entries use claimed range in km.
-- Each image URL now uses make + model + car search tags.
-- The lock parameter keeps each returned image stable.
-- For production, download and host approved official model images in your own CDN/storage.

INSERT INTO car (
    make,
    model,
    variant,
    price_in_lakhs,
    body_type,
    fuel_type,
    transmission,
    mileage,
    seating_capacity,
    safety_rating,
    segment,
    image_url
)
